        /// <summary>
        /// Demonstrates database query logging with parameter sanitization.
        /// </summary>
        private static async Task<object> ExecuteDatabaseQueryWithLogging(
            string correlationId, string path, ILogger log)
        {
            // Connection string should come from Azure Key Vault or App Settings, never hardcoded
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            if (string.IsNullOrEmpty(connectionString))
            {
                log.LogWarning("Database connection string not configured. CorrelationId: {CorrelationId}", correlationId);
                return new { message = "Database not configured" };
            }

            const string queryText = @"
                SELECT TOP 10 Id, Name, Category, CreatedDate 
                FROM Items 
                WHERE Category = @Category AND IsActive = @IsActive
                ORDER BY CreatedDate DESC";

            // Log the query text and sanitized parameters
            using var connection = new SqlConnection(connectionString);
            using var command = new SqlCommand(queryText, connection);

            command.Parameters.AddWithValue("@Category", path ?? "default");
            command.Parameters.AddWithValue("@IsActive", true);

            // Sanitize parameters before logging
            var sanitizedParams = LogSanitizer.SanitizeQueryParameters(command.Parameters);

            var queryLog = new DiagnosticLogEntry
            {
                CorrelationId = correlationId,
                Phase = "DatabaseQuery",
                Data = new Dictionary<string, string>
                {
                    ["Query"] = queryText.Trim(),
                    ["Parameters"] = JsonSerializer.Serialize(sanitizedParams),
                    // Log connection metadata but NOT the connection string itself
                    ["Database"] = connection.Database,
                    ["DataSource"] = connection.DataSource,
                    // NEVER log: connection.ConnectionString
                }
            };

            log.LogInformation("Executing database query. {DiagnosticLog}", queryLog.ToString());

            var startTime = DateTime.UtcNow;

            try
            {
                await connection.OpenAsync();

                using var reader = await command.ExecuteReaderAsync();
                var results = new List<Dictionary<string, object>>();

                while (await reader.ReadAsync())
                {
                    var row = new Dictionary<string, object>();
                    for (int i = 0; i < reader.FieldCount; i++)
                    {
                        row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                    }
                    results.Add(row);
                }

                var elapsed = (DateTime.UtcNow - startTime).TotalMilliseconds;

                var resultLog = new DiagnosticLogEntry
                {
                    CorrelationId = correlationId,
                    Phase = "DatabaseResult",
                    Data = new Dictionary<string, string>
                    {
                        ["RowCount"] = results.Count.ToString(),
                        ["ElapsedMs"] = elapsed.ToString("F2"),
                        ["SlowQuery"] = (elapsed > 1000).ToString()
                    }
                };

                log.LogInformation("Database query completed. {DiagnosticLog}", resultLog.ToString());

                if (elapsed > 1000)
                {
                    log.LogWarning("Slow query detected ({ElapsedMs}ms). CorrelationId: {CorrelationId}",
                        elapsed.ToString("F2"), correlationId);
                }

                return results;
            }
            catch (Exception ex)
            {
                var elapsed = (DateTime.UtcNow - startTime).TotalMilliseconds;

                var dbErrorLog = new DiagnosticLogEntry
                {
                    CorrelationId = correlationId,
                    Phase = "DatabaseQueryFailed",
                    Data = new Dictionary<string, string>
                    {
                        ["ElapsedMs"] = elapsed.ToString("F2"),
                        ["Query"] = queryText.Trim(),
                        ["Parameters"] = JsonSerializer.Serialize(sanitizedParams),
                        ["Error"] = LogSanitizer.SanitizeExceptionMessage(ex.Message)
                    }
                };

                log.LogError(ex, "Database query failed. {DiagnosticLog}", dbErrorLog.ToString());
                throw;
            }
        }
